import React, { useState, useEffect, useRef } from 'react'
import { useHistory } from 'react-router-dom'
import {
  CButton,
  CCard,
  CCardBody,
  CCol,
  CContainer,
  CForm,
  CFormInput,
  CInputGroup,
  CInputGroupText,
  CRow,
  CSpinner,
  CToaster,
  CFormSelect,
} from '@coreui/react'
import CIcon from '@coreui/icons-react'
import {
  cilPhone,
  cilUser,
  cibGmail,
  cilEducation,
  cilBook,
  cilArrowThickLeft,
} from '@coreui/icons'
import axios from 'axios'
import Notify from 'src/utils/Notify'

const Register = () => {
  const [validated, setValidated] = useState(false)
  const [message, setMessage] = useState(null)
  const [error, setError] = useState(false)
  const [toast, addToast] = useState(0)
  const toaster = useRef()
  const [forgotMatricForm, setForgotMatricForm] = useState({})
  const [progFromServer, setProgFromServer] = useState(null)

  useEffect(() => {
    const getProgrammes = async () => {
      const resFromServer = await fetchProgrammes()
      resFromServer ? setProgFromServer(resFromServer) : setProgFromServer(null)
    }
    getProgrammes()
  }, [])

  useEffect(() => {
    if (message) addToast(notify)
  }, [message])

  const notify = <Notify error={error} message={message} />
  const history = useHistory()

  const fetchProgrammes = async () => {
    const res = await fetch('https://records.run.edu.ng/api/app/list_programmes')
    const data = await res.json()
    return data
  }

  const handleForgotMatricChange = (e) => {
    const { id, value } = e.target
    setForgotMatricForm((prevState) => ({
      ...prevState,
      [id]: value,
    }))
  }

  const handleForgotMatric = (e) => {
    e.preventDefault()
    setMessage(null)
    setError(false)
    const form = e.currentTarget
    if (form.checkValidity() === false) {
      e.stopPropagation()
      return
    }
    setValidated(true)
    axios
      .post('https://records.run.edu.ng/api/app/save_forgot_matno', {
        surname: forgotMatricForm.surname,
        firstname: forgotMatricForm.firstname,
        othername: forgotMatricForm.othername,
        email: forgotMatricForm.email,
        phone: forgotMatricForm.phone,
        program: forgotMatricForm.program,
        date_left: forgotMatricForm.date_left,
      })
      .then((res) => {
        setError(false)
        setMessage(res.data.message)
        setValidated(false)
      })
      .catch((err) => {
        setError(true)
        setValidated(false)
        if (err.response) {
          console.log(err.response)
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const goBack = () => {
    history.push('/')
  }

  let startYear = 2009
  let thisYear = new Date().getFullYear()
  let offset = thisYear - startYear
  let allYears = []
  for (let x = 0; x <= offset; x++) {
    allYears.push(startYear + x)
  }

  const yearList = allYears.map((x) => {
    return (
      <option value={x} key={x}>
        {x}
      </option>
    )
  })

  return (
    <div className="bg-light min-vh-100 d-flex flex-row align-items-center">
      <CContainer>
        <CRow className="justify-content-center">
          <CCol md={9} lg={7} xl={6}>
            <CCard className="mx-4">
              <CCardBody className="p-4">
                <CButton onClick={() => goBack()} color="dark" shape="rounded-pill">
                  <CIcon icon={cilArrowThickLeft} /> Go back
                </CButton>
                <CForm noValidate validated={validated} onSubmit={handleForgotMatric}>
                  <h1>Forgot Matric Number</h1>
                  <p className="text-medium-emphasis">
                    Fill the details below to retrieve your matric number
                  </p>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cilUser} />
                    </CInputGroupText>
                    <CFormInput
                      id="surname"
                      type="text"
                      onChange={handleForgotMatricChange}
                      required
                      placeholder="Surname"
                    />
                  </CInputGroup>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cilUser} />
                    </CInputGroupText>
                    <CFormInput
                      id="firstname"
                      type="text"
                      onChange={handleForgotMatricChange}
                      required
                      placeholder="Firstname"
                    />
                  </CInputGroup>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cilUser} />
                    </CInputGroupText>
                    <CFormInput
                      id="othername"
                      type="text"
                      onChange={handleForgotMatricChange}
                      placeholder="Othername"
                    />
                  </CInputGroup>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cibGmail} />
                    </CInputGroupText>
                    <CFormInput
                      id="email"
                      type="email"
                      onChange={handleForgotMatricChange}
                      required
                      placeholder="Email"
                      autoComplete="email"
                    />
                  </CInputGroup>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cilPhone} />
                    </CInputGroupText>
                    <CFormInput
                      id="phone"
                      type="tel"
                      onChange={handleForgotMatricChange}
                      required
                      placeholder="Phone number"
                    />
                  </CInputGroup>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cilBook} />
                    </CInputGroupText>
                    <CFormSelect id="program" onChange={handleForgotMatricChange} required>
                      <option value="">Select Programme</option>
                      {progFromServer &&
                        progFromServer.map((prog) => (
                          <option key={prog.prog_code} value={prog.prog_code}>
                            {prog.programme}
                          </option>
                        ))}
                    </CFormSelect>
                  </CInputGroup>
                  <CInputGroup className="mb-3">
                    <CInputGroupText>
                      <CIcon icon={cilEducation} />
                    </CInputGroupText>
                    <CFormSelect id="date_left" onChange={handleForgotMatricChange} required>
                      <option value="">Select Graduation Year</option>
                      {yearList}
                    </CFormSelect>
                  </CInputGroup>
                  <div className="d-grid">
                    <CButton disabled={validated} type="submit" color="primary">
                      {validated && (
                        <CSpinner
                          component="span"
                          size="sm"
                          color="light"
                          variant="grow"
                          aria-hidden="true"
                        />
                      )}
                      Submit
                    </CButton>
                  </div>
                </CForm>
              </CCardBody>
            </CCard>
          </CCol>
        </CRow>
      </CContainer>
      <CToaster ref={toaster} push={toast} placement="top-end" />
    </div>
  )
}

export default Register
